+namespace deep_gemm {
+template <typename T>
+static CUtensorMap make_2d_tma_a_desc(T* global_address, uint32_t shape_m, uint32_t shape_k,
+                                      uint32_t block_m, uint32_t block_k, uint32_t num_groups,
+                                      GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::RowMajor,
+                          shape_m * (gemm_type == GemmType::GroupedMasked ? num_groups : 1),
+                          shape_k, block_m, block_k, global_stride_in_bytes);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_b_desc(T* global_address, uint32_t shape_n, uint32_t shape_k,
+                               uint32_t block_n, uint32_t block_k, uint32_t num_groups,
+                               GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::ColMajor, shape_k,
+                          shape_n * (gemm_type != GemmType::Normal ? num_groups : 1), block_k,
+                          block_n, global_stride_in_bytes);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_d_desc(T* global_address, uint32_t shape_m, uint32_t shape_n,
+                               uint32_t block_m, uint32_t block_n, uint32_t num_groups,
+                               GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::RowMajor,
+                          shape_m * (gemm_type == GemmType::GroupedMasked ? num_groups : 1),
+                          shape_n, min(block_m, shape_m), min(block_n, shape_n),
+                          global_stride_in_bytes, CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_scales_a_desc(T* global_address, uint32_t shape_m, uint32_t shape_k,
+                                      uint32_t block_m, uint32_t block_k, uint32_t num_groups,
+                                      GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  // Make TMA aligned to 16 bytes
+  constexpr uint32_t kAlignment = 16 / sizeof(T);
+  shape_m = ceil_div(shape_m, kAlignment) * kAlignment;
+
+  return make_2d_tma_desc(
+      global_address, Layout::ColMajor, shape_m,
+      ceil_div(shape_k, block_k) *
+          ((gemm_type == GemmType::GroupedMasked || gemm_type == GemmType::StridedBatched)
+               ? num_groups
+               : 1),
+      block_m, 1, global_stride_in_bytes, CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_tma_scales_a_offset_desc(T* global_address, int64_t max_m_padded_total,
+                                          uint32_t shape_k, uint32_t block_m, uint32_t block_k,
+                                          uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::ColMajor, max_m_padded_total,
+                          ceil_div(shape_k, block_k), block_m, 1, global_stride_in_bytes,
+                          CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_a_desc_swapAB(T* global_address, uint32_t shape_m, uint32_t shape_k,
+                                      uint32_t block_m, uint32_t block_k, uint32_t num_groups,
+                                      GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::RowMajor,
+                          shape_m * (gemm_type != GemmType::Normal ? num_groups : 1), shape_k,
+                          block_m, block_k, global_stride_in_bytes);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_b_desc_swapAB(T* global_address, uint32_t shape_n, uint32_t shape_k,
+                                      uint32_t block_n, uint32_t block_k, uint32_t num_groups,
+                                      GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::ColMajor, shape_k,
+                          shape_n * (gemm_type == GemmType::GroupedMasked ? num_groups : 1),
+                          block_k, block_n, global_stride_in_bytes);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_d_desc_swapAB(T* global_address, uint32_t shape_m, uint32_t shape_n,
+                                      uint32_t block_m, uint32_t block_n, uint32_t num_groups,
+                                      GemmType gemm_type, uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::RowMajor,
+                          shape_n * (gemm_type == GemmType::GroupedMasked ? num_groups : 1),
+                          shape_m, min(block_n, shape_n), min(block_m, shape_m),
+                          global_stride_in_bytes, CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_scales_b_desc_swapAB(T* global_address, uint32_t shape_n, uint32_t shape_k,
+                                             uint32_t block_n, uint32_t block_k,
+                                             uint32_t num_groups, GemmType gemm_type,
+                                             uint64_t global_stride_in_bytes = 0) {
+  // Make TMA aligned to 16 bytes
+  constexpr uint32_t kAlignment = 16 / sizeof(T);
+  shape_n = ceil_div(shape_n, kAlignment) * kAlignment;
+
+  return make_2d_tma_desc(
+      global_address, Layout::RowMajor,
+      ceil_div(shape_k, block_k) *
+          ((gemm_type == GemmType::GroupedMasked || gemm_type == GemmType::StridedBatched)
+               ? num_groups
+               : 1),
+      shape_n, 1, block_n, global_stride_in_bytes, CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_tma_scales_b_offset_desc_swapAB(T* global_address, int64_t max_n_padded_total,
+                                                 uint32_t shape_k, uint32_t block_n,
+                                                 uint32_t block_k,
+                                                 uint64_t global_stride_in_bytes = 0) {
+  return make_2d_tma_desc(global_address, Layout::RowMajor, ceil_div(shape_k, block_k),
+                          max_n_padded_total, 1, block_n, global_stride_in_bytes,
+                          CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_NONE);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_desc(
+    T* global_address, Layout layout, uint32_t gmem_rows, uint32_t gmem_cols, uint32_t smem_rows,
+    uint32_t smem_cols, uint64_t global_stride_in_bytes,
+    CUtensorMapSwizzle swizzle_type = CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_128B) {
+  if (layout == Layout::RowMajor) {
+    uint64_t gmem_dim[2] = {gmem_cols, gmem_rows};
+    uint32_t smem_dim[2] = {smem_cols, smem_rows};
+    global_stride_in_bytes =
+        global_stride_in_bytes ? global_stride_in_bytes : gmem_cols * sizeof(T);
+    return make_2d_tma_copy_desc(global_address, gmem_dim, global_stride_in_bytes, smem_dim,
+                                 swizzle_type);
+  } else {
+    uint64_t gmem_dim[2] = {gmem_rows, gmem_cols};
+    uint32_t smem_dim[2] = {smem_rows, smem_cols};
+    global_stride_in_bytes =
+        global_stride_in_bytes ? global_stride_in_bytes : gmem_rows * sizeof(T);
+    return make_2d_tma_copy_desc(global_address, gmem_dim, gmem_rows * sizeof(T), smem_dim,
+                                 swizzle_type);
+  }
+}
