+void runGemm(cudaKernel_t kernel, void* mat_a, uint64_t ld_a, uint64_t stride_a, void* mat_b,
+             uint64_t ld_b, uint64_t stride_b, void* mat_d, uint64_t ld_d, uint64_t stride_d,
