+  auto tma_b_desc = make_2d_tma_b_desc(reinterpret_cast<__nv_fp8_e4m3*>(mat_b), shape_n, shape_k,
+                                       block_n, block_k, num_groups, gemm_type, ld_b);
+  auto tma_scales_a_desc = make_2d_tma_scales_a_desc(scales_a, shape_m, shape_k, block_m, block_k,
+                                                     num_groups, gemm_type);
+  auto tma_d_desc = make_2d_tma_d_desc(reinterpret_cast<__nv_bfloat16*>(mat_d), shape_m, shape_n,
+                                       block_m, block_n, num_groups, gemm_type, ld_d * 2);
+  constexpr uint32_t kNumTMAThreads = 128;
+  constexpr uint32_t kNumMathThreadsPerGroup = 128;
+  DG_HOST_ASSERT(cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize,
+                                      smem_size) == cudaSuccess);
+
+  // Cluster launch
+  cudaLaunchConfig_t config;
+  config.gridDim = num_sms;
+  config.blockDim = get_num_threads_per_sm<kNumTMAThreads, kNumMathThreadsPerGroup>(
+      static_cast<int32_t>(block_m));
+  config.dynamicSmemBytes = smem_size;
+  config.stream = stream;
+
+  // Clusters for TMA multicast
+  // NOTES: `>= 4` cluster size will cause performance degradation
+  cudaLaunchAttribute attr;
+  attr.id = cudaLaunchAttributeClusterDimension;
+  attr.val.clusterDim = {num_tma_multicast, 1, 1};
+  config.attrs = &attr;
+  config.numAttrs = 1;
+
+  StridedBatchedSchedulerInput input{shape_m, ld_a, stride_a, ld_b, stride_b, ld_d, stride_d};
+  // Launch
+  auto status =
+      cudaLaunchKernelEx(&config, kernel, reinterpret_cast<__nv_bfloat16*>(mat_d), scales_b, input,
+                         tma_a_desc, tma_b_desc, tma_scales_a_desc, tma_d_desc);
+  DG_HOST_ASSERT(status == cudaSuccess);
+}
