+PFN_cuTensorMapEncodeTiled_v12000 get_cuTensorMapEncodeTiled() {
+  // Get pointer to `cuTensorMapEncodeTiled`
+  cudaDriverEntryPointQueryResult driver_status;
+  void* cuTensorMapEncodeTiled_ptr = nullptr;
+
+#if CUDA_VERSION >= 12050
+  cudaGetDriverEntryPointByVersion("cuTensorMapEncodeTiled", &cuTensorMapEncodeTiled_ptr, 12000,
+                                   cudaEnableDefault, &driver_status);
+#else
+  cudaGetDriverEntryPoint("cuTensorMapEncodeTiled", &cuTensorMapEncodeTiled_ptr, cudaEnableDefault,
+                          &driver_status);
+#endif
+
+  if (driver_status != cudaDriverEntryPointSuccess)
+    throw std::runtime_error("driver_status != cudaDriverEntryPointSuccess");
+  return reinterpret_cast<PFN_cuTensorMapEncodeTiled_v12000>(cuTensorMapEncodeTiled_ptr);
+}
+
+template <typename T>
+CUtensorMap make_2d_tma_copy_desc(T* global_address, uint64_t gmem_dim[2], uint64_t stride_in_bytes,
+                                  uint32_t smem_dim[2], CUtensorMapSwizzle swizzle_type,
+                                  PFN_cuTensorMapEncodeTiled_v12000 encode_func = nullptr) {
+  CUtensorMap tensor_map{};
+  constexpr uint32_t rank = 2;
+  uint64_t global_stride[rank - 1] = {stride_in_bytes};
+  uint32_t elem_strides[rank] = {1, 1};
+
+  if (encode_func == nullptr) encode_func = get_cuTensorMapEncodeTiled();
+
+  auto result =
+      encode_func(&tensor_map, get_CUtensorMapDataType<typename std::remove_cv<T>::type>(), rank,
+                  global_address, gmem_dim, global_stride, smem_dim, elem_strides,
+                  CUtensorMapInterleave::CU_TENSOR_MAP_INTERLEAVE_NONE, swizzle_type,
+                  CUtensorMapL2promotion::CU_TENSOR_MAP_L2_PROMOTION_L2_256B,
+                  CUtensorMapFloatOOBfill::CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE);
+  DG_HOST_ASSERT(result == CUDA_SUCCESS);
+  return tensor_map;
+}
