+  if ((!is_act) && internal_quantize_b) {
+    return div_up(shape_m * shape_n * sizeof(__nv_fp8_e4m3), 128) * 128;
+  }
+  return 0;
+#else   // ENABLE_FP8_BLOCK_SCALE
