+__inline__ __device__ uint32_t elect_one_sync([[maybe_unused]] int lane_id) {
+  uint32_t pred = 0;
+#if __CUDA_ARCH__ >= 900
+  uint32_t laneid = 0;
+  asm volatile(
+      "\n\
+    {\n\
+        .reg .b32 %rx;\n\
+        .reg .pred %px;\n\
+        elect.sync %rx|%px, %2;\n\
+        @%px mov.s32 %1, 1;\n\
+        mov.s32 %0, %rx;\n\
+    }\n\
+  "
+      : "+r"(laneid), "+r"(pred)
+      : "r"(0xFFFFFFFF));
+#else
+  return lane_id == 0;
+#endif
+  return pred;
+}
