+  struct Input {
+    int64_t const* problem_m_offsets;
+  };
+
+  static __host__ __device__ dim3 grid_dim(int shape_m, int shape_n, int num_problems) {
+    return dim3(div_up(shape_m, TILE_M), div_up(shape_n, TILE_N), num_problems);
