+void fp8_1x128_cs(__nv_fp8_e4m3* mat_quant, float* scales, __nv_bfloat16 const* mat, int shape_x,
+                  int shape_y, cudaStream_t stream) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  scale_1x128_kernel<<<kNumDeviceSMs * 8, 256, 0, stream>>>(mat_quant, scales, mat, shape_x,
+                                                            shape_y);
+}
+
+void fp8_1x128_cs_reshape(__nv_fp8_e4m3* mat_quant, float* scales, __nv_bfloat16 const* mat,
+                          int shape_x, int shape_h, int shape_y, int stride_x,
+                          cudaStream_t stream) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  scale_1x128_reshape_kernel<<<kNumDeviceSMs * 8, 256, 0, stream>>>(mat_quant, scales, mat, shape_x,
+                                                                    shape_h, shape_y, stride_x);
+}
+
+void fp8_128x128_cs(__nv_fp8_e4m3* mat_quant, float* scales, __nv_bfloat16 const* mat, int shape_x,
+                    int shape_y, cudaStream_t stream) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  convert_kernel<<<kNumDeviceSMs, 256, 0, stream>>>(mat_quant, mat, shape_x * shape_y);
+  fill_kernel<<<kNumDeviceSMs, 256, 0, stream>>>(scales,
+                                                 div_up(shape_x, 128) * div_up(shape_y, 128), 1);
+}
+
+void gemm_dispatch_old(void* mat_a, int ld_a, void* mat_b, int ld_b, void* mat_d, int ld_d,
+                       float* scales_a, float* scales_b, int shape_m, int shape_n, int shape_k,
+                       cudaStream_t stream) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  auto get_status = [=](int tile_n) -> std::pair<int, int> {
+    int num_blocks = div_up(shape_n, tile_n);
+    int num_waves = div_up(num_blocks, kNumDeviceSMs);
+    return {num_waves, num_blocks % kNumDeviceSMs};
+  };
+
+  auto compare = [=](int tile_n, int old_block_n) -> bool {
+    if (old_block_n == 0) return true;
+
+    auto status = get_status(tile_n);
+    auto old_status = get_status(old_block_n);
+    if (status.first != old_status.first) return status.first < old_status.first;
+    if (status.first == 1) return status.second > old_status.second;
+    return tile_n > old_block_n;
+  };
+
+  int best_tile_m = shape_m <= 64 ? 64 : 128, best_block_n = 0;
+  for (auto const& tile_n : {32, 64, 128})
+    if (compare(tile_n, best_block_n)) best_block_n = tile_n;
+
+#define DISPATCH_BLOCK_SIZE(TILE_M, TILE_N)                                                      \
+  {                                                                                              \
+    using GemmType =                                                                             \
+        Fp8Gemm<__nv_fp8_e4m3, Layout::RowMajor, __nv_fp8_e4m3, Layout::ColMajor, __nv_bfloat16, \
+                Layout::RowMajor, float, float, float, TILE_M, TILE_N, 128,                      \
+                ScaleType::PerSubChannel, ScaleType::PerBlock, 1, 128, 128, 128>;                \
+    GemmType::run(reinterpret_cast<__nv_fp8_e4m3*>(mat_a), ld_a,                                 \
+                  reinterpret_cast<__nv_fp8_e4m3*>(mat_b), ld_b,                                 \
+                  reinterpret_cast<__nv_bfloat16*>(mat_d), ld_d, scales_a, scales_b, shape_m,    \
+                  shape_n, shape_k, stream                                                       \
+                                                                                                 \
+    );                                                                                           \
+  }                                                                                              \
+  break
+
+#define DISPATCH_BLOCK_SIZE_M(TILE_N)     \
+  {                                       \
+    switch (best_tile_m) {                \
+      case 64:                            \
+        DISPATCH_BLOCK_SIZE(64, TILE_N);  \
+      case 128:                           \
+        DISPATCH_BLOCK_SIZE(128, TILE_N); \
+    }                                     \
+  }                                       \
+  break
+
+  switch (best_block_n) {
+    case 16:
+      DISPATCH_BLOCK_SIZE_M(16);
+    case 32:
+      DISPATCH_BLOCK_SIZE_M(32);
+    case 64:
+      DISPATCH_BLOCK_SIZE_M(64);
+    case 128:
+      DISPATCH_BLOCK_SIZE_M(128);
+  }
+#undef DISPATCH_BLOCK_SIZE
+#undef DISPATCH_BLOCK_SIZE_M
+}
+
+void gemm_dispatch_old(void* mat_a, void* mat_b, void* mat_d, float* scales_a, float* scales_b,
+                       int num_problems, int64_t const* problem_m_offsets, int max_shape_m,
+                       int shape_n, int shape_k, cudaStream_t stream) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  auto get_status = [=](int tile_n) -> std::pair<int, int> {
+    int num_blocks = div_up(shape_n, tile_n);
+    int num_waves = div_up(num_blocks, kNumDeviceSMs);
+    return {num_waves, num_blocks % kNumDeviceSMs};
+  };
+
+  auto compare = [=](int tile_n, int old_block_n) -> bool {
+    if (old_block_n == 0) return true;
+
+    auto status = get_status(tile_n), old_status = get_status(old_block_n);
+    if (status.first != old_status.first) return status.first < old_status.first;
+    if (status.first == 1) return status.second > old_status.second;
+    return tile_n > old_block_n;
+  };
+
+  int shape_m = 128;
+  int best_tile_m = shape_m <= 64 ? 64 : 128, best_block_n = 0;
+  for (auto const& tile_n : {64, 128})
+    if (compare(tile_n, best_block_n)) best_block_n = tile_n;
+
+#define DISPATCH_BLOCK_SIZE(TILE_M, TILE_N)                                                      \
+  {                                                                                              \
+    using GemmType =                                                                             \
+        Fp8Gemm<__nv_fp8_e4m3, Layout::RowMajor, __nv_fp8_e4m3, Layout::ColMajor, __nv_bfloat16, \
+                Layout::RowMajor, float, float, float, TILE_M, TILE_N, 128,                      \
+                ScaleType::PerSubChannel, ScaleType::PerBlock, 1, 128, 128, 128>;                \
+    GemmType::run(reinterpret_cast<__nv_fp8_e4m3*>(mat_a),                                       \
+                  reinterpret_cast<__nv_fp8_e4m3*>(mat_b),                                       \
+                  reinterpret_cast<__nv_bfloat16*>(mat_d), scales_a, scales_b, num_problems,     \
+                  problem_m_offsets, shape_n, shape_k, max_shape_m, stream                       \
+                                                                                                 \
+    );                                                                                           \
+  }                                                                                              \
+  break
+
+#define DISPATCH_BLOCK_SIZE_M(TILE_N)     \
+  {                                       \
+    switch (best_tile_m) {                \
+      case 64:                            \
+        DISPATCH_BLOCK_SIZE(64, TILE_N);  \
+      case 128:                           \
+        DISPATCH_BLOCK_SIZE(128, TILE_N); \
+    }                                     \
+  }                                       \
+  break
+
+  switch (best_block_n) {
+    case 16:
+      DISPATCH_BLOCK_SIZE_M(16);
+    case 32:
+      DISPATCH_BLOCK_SIZE_M(32);
+    case 64:
+      DISPATCH_BLOCK_SIZE_M(64);
+    case 128:
+      DISPATCH_BLOCK_SIZE_M(128);
+  }
+#undef DISPATCH_BLOCK_SIZE
+#undef DISPATCH_BLOCK_SIZE_M
+}
+
+void gemm_dispatch(void* mat_a, int ld_a, void* mat_b, int ld_b, void* mat_d, int ld_d,
+                   float* scales_a, float* scales_b, uint32_t shape_m, uint32_t shape_n,
+                   uint32_t shape_k, cudaStream_t stream, int num_device_sms = kNumDeviceSMs) {
+  if (num_device_sms < 0) {
+    num_device_sms = kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+
+  constexpr uint32_t block_k = 128;
+  constexpr uint32_t num_problems = 1;
+
+  uint32_t m_threshold = 32;
+  if (shape_m >= m_threshold) {
+    // Select the best configuration based on shape dimensions
+    auto [best_block_m, best_block_n, best_num_stages, best_num_tma_multicast, best_smem_size] =
+        deep_gemm::jit::get_best_gemm_config(shape_m, shape_n, shape_k, num_problems,
+                                             num_device_sms);
+
+    auto runtime = deep_gemm::jit::getGlobalCompiler().build(
+        shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems, best_num_stages,
+        best_num_tma_multicast, deep_gemm::GemmType::Normal);
+    auto kernel = reinterpret_cast<cudaKernel_t>(runtime->getKernel());
+    deep_gemm::runGemm(kernel, mat_a, ld_a, mat_b, ld_b, mat_d, ld_d, scales_a, scales_b, shape_m,
+                       shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems,
+                       best_num_tma_multicast, deep_gemm::GemmType::Normal,
+                       static_cast<int*>(nullptr), stream, num_device_sms,
+                       static_cast<uint32_t>(best_smem_size));
+  } else {
+    auto [best_block_m, best_block_n, best_num_stages, best_num_tma_multicast, best_smem_size] =
+        deep_gemm::jit::get_best_gemm_config(shape_n, shape_m, shape_k, num_problems,
+                                             num_device_sms, false, true);
+    auto runtime = deep_gemm::jit::getGlobalCompiler().build(
+        shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems, best_num_stages,
+        best_num_tma_multicast, deep_gemm::GemmType::Normal, true);
+    auto kernel = reinterpret_cast<cudaKernel_t>(runtime->getKernel());
+    deep_gemm::runGemmSwapAB(kernel, mat_b, ld_b, mat_a, ld_a, mat_d, ld_d, scales_b, scales_a,
+                             shape_n, shape_m, shape_k, best_block_m, best_block_n, block_k,
+                             num_problems, best_num_tma_multicast, deep_gemm::GemmType::Normal,
+                             static_cast<int*>(nullptr), stream, num_device_sms,
+                             static_cast<uint32_t>(best_smem_size));
+  }
+}
+
+void gemm_dispatch_sm89(void* mat_a, void* mat_b, void* mat_d, float* scales_a, float* scales_b,
+                        uint32_t shape_m, uint32_t shape_n, uint32_t shape_k, cudaStream_t stream,
+                        int num_device_sms = kNumDeviceSMs) {
+  if (num_device_sms < 0) {
+    num_device_sms = kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  using ElementInput = cute::float_e4m3_t;
+  using ElementOutput = cute::bfloat16_t;
+  using ElementAccum = float;
+  using ElementBlockScale = float;
+  static constexpr int Stages = 3;
+  using TileShape = cutlass::gemm::GemmShape<32, 128, 128>;
+  using KT = ada_blockwise_gemm::AdaBlockwiseGemmTraits<ElementInput, ElementOutput, ElementAccum,
+                                                        ElementBlockScale, Stages, TileShape::kM,
+                                                        TileShape::kN, TileShape::kK>;
+  using GemmKernel = ada_blockwise_gemm::AdaBlockwiseGemmKernel<KT>;
+
+  static constexpr int kSmemSize = KT::kSmemSize;
+  static constexpr int kThreadCount = KT::kThreadCount;
+  int grid_m = (shape_m + KT::kTileM - 1) / KT::kTileM;
+  int grid_n = (shape_n + KT::kTileN - 1) / KT::kTileN;
+  int grid_k = 1;
+  dim3 grid = dim3(grid_m, grid_n, grid_k);
+  dim3 block = dim3(kThreadCount, 1, 1);
+
+  if (kSmemSize > (48 << 10)) {
+    cudaFuncSetAttribute(ada_blockwise_gemm::sm89_fp8_gemm_1d1d_impl<GemmKernel>,
+                         cudaFuncAttributeMaxDynamicSharedMemorySize, kSmemSize);
+    auto result = cudaGetLastError();
+    TLLM_CHECK_WITH_INFO(result == cudaSuccess, "sm89 gemm kernel cannot launch: %s",
+                         cudaGetErrorString(result));
+  }
+
+  ada_blockwise_gemm::sm89_fp8_gemm_1d1d_impl<GemmKernel><<<grid, block, kSmemSize, stream>>>(
+      shape_m, shape_n, shape_k, mat_a, mat_b, mat_d, scales_a, scales_b);
+}
+
+void fp8_gemm_run(__nv_fp8_e4m3* mat_a, int ld_a, __nv_fp8_e4m3* mat_b, int ld_b,
+                  __nv_bfloat16* mat_d, int ld_d, uint32_t shape_m, uint32_t shape_n,
+                  uint32_t shape_k, float* scales_a, float* scales_b, cudaStream_t stream) {
+  if (shape_m == 0) {
+    return;
+  }
+#ifndef PLACEHOLDER_KERNELS
+  int arch = tensorrt_llm::common::getSMVersion();
+  if (arch == 89) {
+    gemm_dispatch_sm89(mat_a, mat_b, mat_d, scales_a, scales_b, shape_m, shape_n, shape_k, stream);
+    return;
+  }
+  if (kDeepGemmEnabled) {
+    gemm_dispatch(mat_a, ld_a, mat_b, ld_b, mat_d, ld_d, scales_a, scales_b, shape_m, shape_n,
+                  shape_k, stream);
+  } else {
+    gemm_dispatch_old(mat_a, ld_a, mat_b, ld_b, mat_d, ld_d, scales_a, scales_b,
+                      static_cast<int>(shape_m), static_cast<int>(shape_n),
+                      static_cast<int>(shape_k), stream);
+  }
+#endif
+}
+
+void fp8_gemm_run(__nv_bfloat16 const* mat_a, __nv_fp8_e4m3* fp8_mat_a, int ld_a, float* scales_a,
+                  __nv_bfloat16 const* mat_b, __nv_fp8_e4m3* fp8_mat_b, int ld_b, float* scales_b,
+                  __nv_bfloat16* mat_d, int ld_d, uint32_t shape_m, uint32_t shape_n,
+                  uint32_t shape_k, cudaStream_t stream, bool internal_quantize_a = true,
+                  bool internal_quantize_b = true) {
+  if (shape_m == 0) {
+    return;
+  }
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+
+  if (internal_quantize_a) {
+    scale_1x128_kernel<<<kNumDeviceSMs * 8, 256, 0, stream>>>(fp8_mat_a, scales_a, mat_a, shape_k,
+                                                              shape_m);
+  }
+  if (internal_quantize_b) {
+    scale_128x128_kernel<<<kNumDeviceSMs, 256, 0, stream>>>(fp8_mat_b, scales_b, mat_b, shape_k,
+                                                            shape_n);
+  }
+  fp8_gemm_run(fp8_mat_a, ld_a, fp8_mat_b, ld_b, mat_d, ld_d, shape_m, shape_n, shape_k, scales_a,
+               scales_b, stream);
+}
+
+void grouped_gemm_dispatch(__nv_fp8_e4m3* mat_a, __nv_fp8_e4m3* mat_b, __nv_bfloat16* mat_d,
+                           uint32_t num_problems, int64_t const* problem_m_offsets,
+                           uint32_t expected_m, uint32_t max_shape_m, uint32_t max_shape_m_padded,
+                           uint32_t shape_n, uint32_t shape_k, float* scales_a, float* scales_b,
+                           cudaStream_t stream, int num_device_sms = kNumDeviceSMs) {
+  if (num_device_sms < 0) {
+    num_device_sms = kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+
+  constexpr uint32_t block_k = 128;
+  uint32_t m_per_expert_threshold =
+      num_device_sms == 78 ? 64 : 32;  // 64 for H20(sms=78), 32 for H100/H200
+  if (expected_m >= m_per_expert_threshold) {
+    auto [best_block_m, best_block_n, best_num_stages, best_num_tma_multicast, best_smem_size] =
+        deep_gemm::jit::get_best_gemm_config(expected_m, shape_n, shape_k, num_problems,
+                                             num_device_sms);
+
+    auto runtime = deep_gemm::jit::getGlobalCompiler().build(
+        shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems, best_num_stages,
+        best_num_tma_multicast, deep_gemm::GemmType::GroupedWithOffset);
+    auto kernel = reinterpret_cast<cudaKernel_t>(runtime->getKernel());
+    deep_gemm::runGemm(kernel, mat_a, 0, mat_b, 0, mat_d, 0, scales_a, scales_b, max_shape_m,
+                       shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems,
+                       best_num_tma_multicast, deep_gemm::GemmType::GroupedWithOffset,
+                       const_cast<int64_t*>(problem_m_offsets), stream, num_device_sms,
+                       static_cast<uint32_t>(best_smem_size), max_shape_m_padded);
+  } else {
+    auto [best_block_m, best_block_n, best_num_stages, best_num_tma_multicast, best_smem_size] =
+        deep_gemm::jit::get_best_gemm_config(shape_n, expected_m, shape_k, num_problems,
+                                             num_device_sms, false, true);
+    auto runtime = deep_gemm::jit::getGlobalCompiler().build(
+        shape_n, shape_k, best_block_m, best_block_n, block_k, num_problems, best_num_stages,
+        best_num_tma_multicast, deep_gemm::GemmType::GroupedWithOffset, true);
+    auto kernel = reinterpret_cast<cudaKernel_t>(runtime->getKernel());
+
+    deep_gemm::runGemmSwapAB(
+        kernel, mat_b, 0, mat_a, 0, mat_d, 0, scales_b, scales_a, shape_n, max_shape_m, shape_k,
+        best_block_m, best_block_n, block_k, num_problems, best_num_tma_multicast,
+        deep_gemm::GemmType::GroupedWithOffset, const_cast<int64_t*>(problem_m_offsets), stream,
+        num_device_sms, static_cast<uint32_t>(best_smem_size), max_shape_m_padded);
+  }
+}
+
+void fp8_grouped_gemm_run(__nv_bfloat16 const* mat_a, __nv_fp8_e4m3* fp8_mat_a, float* scales_a,
+                          __nv_bfloat16 const* mat_b, __nv_fp8_e4m3* fp8_mat_b, float* scales_b,
+                          __nv_bfloat16* mat_d, int64_t const* problem_m_offsets, int num_problems,
+                          int64_t expected_m, int64_t max_shape_m, int64_t max_shape_m_padded,
+                          int shape_n, int shape_k, cudaStream_t stream,
+                          bool internal_quantize_a = true, bool internal_quantize_b = true) {
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+
+  if (internal_quantize_a) {
+    constexpr int NumThreads = 256;
+    int scales_dim_x = div_up(shape_k, 128);
+    uint32_t scale_dim_x_mul, scale_dim_x_shr;
+    kernel_utils::find_divisor(scale_dim_x_mul, scale_dim_x_shr, scales_dim_x);
+
+    int smem_size = num_problems * sizeof(int64_t);
+    int num_blocks = std::min(static_cast<int64_t>(kNumDeviceSMs),
+                              div_up(max_shape_m * scales_dim_x, NumThreads / 32));
+    // Binary search is expected to have lower complexity when max_shape_m is small
+    bool use_binary_search =
+        static_cast<double>(max_shape_m) * scales_dim_x /
+            static_cast<double>(NumThreads * num_blocks / 32) <=
+        static_cast<double>(num_problems) / std::log2(static_cast<double>(num_problems));
+    auto kernel = use_binary_search ? scale_1x128_kernel<true, __nv_bfloat16, __nv_fp8_e4m3>
+                                    : scale_1x128_kernel<false, __nv_bfloat16, __nv_fp8_e4m3>;
+    cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size);
+    kernel<<<num_blocks, NumThreads, smem_size, stream>>>(
+        fp8_mat_a, scales_a, mat_a, problem_m_offsets, num_problems, shape_k, max_shape_m_padded,
+        scale_dim_x_mul, scale_dim_x_shr);
+  }
+
+  if (internal_quantize_b) {
+    __nv_fp8_e4m3* fp8_mat_b_tmp = fp8_mat_b;
+    float* scales_b_tmp = scales_b;
+    __nv_bfloat16 const* mat_b_tmp = mat_b;
+
+    for (int i = 0; i < num_problems; i++) {
+      scale_128x128_kernel<<<kNumDeviceSMs, 256, 0, stream>>>(fp8_mat_b_tmp, scales_b_tmp,
+                                                              mat_b_tmp, shape_k, shape_n);
+      fp8_mat_b_tmp += shape_n * shape_k;
+      mat_b_tmp += shape_n * shape_k;
+      scales_b_tmp += div_up(shape_n, 128) * div_up(shape_k, 128);
+    }
+  }
+
+  if (kDeepGemmEnabled) {
+    grouped_gemm_dispatch(fp8_mat_a, fp8_mat_b, mat_d, num_problems, problem_m_offsets, expected_m,
+                          max_shape_m, max_shape_m_padded, shape_n, shape_k, scales_a, scales_b,
+                          stream);
+  } else {
+    using GemmType = Fp8Gemm<__nv_fp8_e4m3, Layout::RowMajor, __nv_fp8_e4m3, Layout::ColMajor,
+                             __nv_bfloat16, Layout::RowMajor, float, float, float, 128, 64, 128,
+                             ScaleType::PerSubChannel, ScaleType::PerBlock, 1, 128, 128, 128>;
+    GemmType::run(fp8_mat_a, fp8_mat_b, mat_d, scales_a, scales_b, num_problems, problem_m_offsets,
+                  shape_n, shape_k, static_cast<int>(max_shape_m), stream, 128,
+                  static_cast<int>(max_shape_m_padded));
+  }
+}
