+void strided_batch_gemm_dispatch_sm89(__nv_fp8_e4m3* mat_a, int ld_a, int stride_a,
+                                      __nv_fp8_e4m3* mat_b, int ld_b, int stride_b,
+                                      __nv_bfloat16* mat_d, int ld_d, int stride_d, float* scales_a,
+                                      int stride_scales_a, float* scales_b, uint32_t num_problems,
+                                      uint32_t shape_m, uint32_t shape_n, uint32_t shape_k,
+                                      cudaStream_t stream, int num_device_sms = kNumDeviceSMs) {
+  if (num_device_sms < 0) {
+    num_device_sms = kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  using ElementInput = cute::float_e4m3_t;
+  using ElementOutput = cute::bfloat16_t;
+  using ElementAccum = float;
+  using ElementBlockScale = float;
+  static constexpr int Stages = 3;
+  using TileShape = cutlass::gemm::GemmShape<32, 128, 128>;
+  using KT = ada_blockwise_gemm::AdaBlockwiseGemmTraits<ElementInput, ElementOutput, ElementAccum,
+                                                        ElementBlockScale, Stages, TileShape::kM,
+                                                        TileShape::kN, TileShape::kK>;
+  using GemmKernel = ada_blockwise_gemm::AdaBlockwiseGemmKernel<KT>;
+
+  static constexpr int kSmemSize = KT::kSmemSize;
+  static constexpr int kThreadCount = KT::kThreadCount;
+  int grid_m = (shape_m + KT::kTileM - 1) / KT::kTileM;
+  int grid_n = (shape_n + KT::kTileN - 1) / KT::kTileN;
+  int grid_k = num_problems;
+  dim3 grid = dim3(grid_m, grid_n, grid_k);
+  dim3 block = dim3(kThreadCount, 1, 1);
+
+  int stride_scales_b = ((shape_n + 128 - 1) / 128) * ((shape_k + 128 - 1) / 128);
+
+  if (kSmemSize > (48 << 10)) {
+    cudaFuncSetAttribute(ada_blockwise_gemm::sm89_fp8_bmm_1d1d_impl<GemmKernel>,
+                         cudaFuncAttributeMaxDynamicSharedMemorySize, kSmemSize);
+    auto result = cudaGetLastError();
+    TLLM_CHECK_WITH_INFO(result == cudaSuccess, "sm89 gemm kernel cannot launch: %s",
+                         cudaGetErrorString(result));
+  }
+  ada_blockwise_gemm::sm89_fp8_bmm_1d1d_impl<GemmKernel><<<grid, block, kSmemSize, stream>>>(
+      shape_m, shape_n, shape_k, mat_a, mat_b, mat_d, scales_a, scales_b, stride_a, stride_b,
+      stride_d, stride_scales_a, stride_scales_b);
+}
+
+void fp8_stride_batch_gemm_run(__nv_bfloat16 const* mat_a, __nv_fp8_e4m3* fp8_mat_a,
+                               float* scales_a, int ld_a, int stride_a, int stride_scales_a,
+                               __nv_bfloat16 const* mat_b, __nv_fp8_e4m3* fp8_mat_b,
+                               float* scales_b, int ld_b, int stride_b, __nv_bfloat16* mat_d,
+                               int ld_d, int stride_d, uint32_t num_problems, uint32_t shape_m,
+                               uint32_t shape_n, uint32_t shape_k, cudaStream_t stream,
+                               bool internal_quantize_a = true, bool internal_quantize_b = true) {
+  if (shape_m == 0) {
+    return;
+  }
+
+  if (kNumDeviceSMs < 0) {
+    kNumDeviceSMs = tensorrt_llm::common::getMultiProcessorCount();
+  }
+  if (internal_quantize_a) {
+    scale_1x128_kernel<<<kNumDeviceSMs * 8, 256, 0, stream>>>(fp8_mat_a, scales_a, mat_a, shape_k,
+                                                              shape_m * num_problems);
+  }
+  if (internal_quantize_b) {
+    scale_128x128_kernel<<<kNumDeviceSMs, 256, 0, stream>>>(fp8_mat_b, scales_b, mat_b, shape_k,
+                                                            shape_n * num_problems);
+  }
+
+  int arch = tensorrt_llm::common::getSMVersion();
+  if (arch == 89) {
+    strided_batch_gemm_dispatch_sm89(fp8_mat_a, ld_a, stride_a, fp8_mat_b, ld_b, stride_b, mat_d,
+                                     ld_d, stride_d, scales_a, stride_scales_a, scales_b,
+                                     num_problems, shape_m, shape_n, shape_k, stream);
+    return;
+  }
+  if (kDeepGemmEnabled) {
+    strided_batch_gemm_dispatch(fp8_mat_a, ld_a, stride_a, fp8_mat_b, ld_b, stride_b, mat_d, ld_d,
+                                stride_d, scales_a, scales_b, num_problems, shape_m, shape_n,
+                                shape_k, stream);
+  } else {
+    using GemmType = Fp8Gemm<__nv_fp8_e4m3, Layout::RowMajor, __nv_fp8_e4m3, Layout::ColMajor,
+                             __nv_bfloat16, Layout::RowMajor, float, float, float, 128, 64, 128,
+                             ScaleType::PerSubChannel, ScaleType::PerBlock, 1, 128, 128, 128>;
+    GemmType::run(fp8_mat_a, ld_a, stride_a, fp8_mat_b, ld_b, stride_b, mat_d, ld_d, stride_d,
+                  scales_a, stride_scales_a, scales_b, static_cast<int>(shape_m),
+                  static_cast<int>(shape_n), static_cast<int>(shape_k),
+                  static_cast<int>(num_problems), stream);
+  }
+}
+
+}  // namespace tensorrt_llm::kernels::fp8_blockscale_gemm

